mapper.select:
SELECT u.ID, u.USER_ACCOUNT, u.PASSWD, u.USER_NAME, u.DEPT_ID, u.IS_SUPERADMIN, CASE u.IS_SUPERADMIN WHEN '1' THEN '是' ELSE '否' END IS_SUPERADMIN_LABEL, u.MOBILE, u.EMAIL, u.STATUS, CASE u.STATUS WHEN 1 THEN '在用' ELSE '停用' END AS STATUS_LABEL, u.REMARK, u.PSD_UPD_DATE, u.SORT_NUM, u.UPDATE_TIME, u.CREATE_TIME, u.POST_CODE, u.POST_NAME, u.UNIT_TYPE_CODE, u.UNIT_TYPE_NAME, u.IS_LABOR, d.DEPT_NAME FROM SYS_USER u JOIN SYS_DEPT d ON u.DEPT_ID = d.ID
u.IS_LABOR = #{isLabor,jdbcType=VARCHAR}
AND (u.USER_ACCOUNT LIKE #{userAccount,jdbcType=VARCHAR})
AND (u.USER_NAME LIKE #{userName,jdbcType=VARCHAR})
AND (instr(d.PARENT_IDS, #{deptId,jdbcType=BIGINT}) > 0 OR d.ID = #{deptId,jdbcType=BIGINT})
AND u.STATUS = #{status}
AND u.IS_SUPERADMIN = #{isSuperadmin}
ORDER BY u.SORT_NUM

